  1→import { logInfo, logError, elapsedMs } from "../http/observability";
  2→import { jsonError } from "../http/response";
  3→
  4→const ANTHROPIC_API_URL = "https://api.anthropic.com";
  5→
  6→const FORWARDED_HEADERS = [
  7→  "anthropic-version",
  8→  "anthropic-beta",
  9→  "content-type",
 10→] as const;
 11→
 12→export function createAnthropicProxyHandler(): (request: Request) => Promise<Response> {
 13→  return (request: Request) => proxyToAnthropic(request);
 14→}
 15→
 16→async function proxyToAnthropic(request: Request): Promise<Response> {
 17→  const startedAt = performance.now();
 18→  const url = new URL(request.url);
 19→  const upstreamPath = url.pathname.replace(/^\/proxy\/llm\/anthropic/, "");
 20→  const upstreamUrl = `${ANTHROPIC_API_URL}${upstreamPath}`;
 21→
 22→  // Forward auth and protocol headers from the client
 23→  const headers = new Headers();
 24→  for (const name of FORWARDED_HEADERS) {
 25→    const value = request.headers.get(name);
 26→    if (value) headers.set(name, value);
 27→  }
 28→  // Forward client's API key — Claude Code sends its own
 29→  const xApiKey = request.headers.get("x-api-key");
 30→  const authHeader = request.headers.get("authorization");
 31→  if (xApiKey) headers.set("x-api-key", xApiKey);
 32→  if (authHeader) headers.set("authorization", authHeader);
 33→
 34→  const body = await request.text();
 35→  let parsed: { model?: string; stream?: boolean; max_tokens?: number; metadata?: { user_id?: string } } | undefined;
 36→  try {
 37→    parsed = JSON.parse(body);
 38→  } catch {
 39→    // not JSON — forward as-is
 40→  }
 41→
 42→  const isStreaming = parsed?.stream === true;
 43→  const identity = parseMetadataUserId(parsed?.metadata?.user_id);
 44→
 45→  logInfo("proxy.anthropic.request", "Forwarding to Anthropic", {
 46→    method: request.method,
 47→    url: upstreamUrl,
 48→    headers: Object.fromEntries(request.headers.entries()),
 49→    body: parsed ?? body,
 50→    ...identity,
 51→  });
 52→
 53→  let upstream: Response;
 54→  try {
 55→    upstream = await fetch(upstreamUrl, {
 56→      method: request.method,
 57→      headers,
 58→      body: request.method !== "GET" ? body : undefined,
 59→    });
 60→  } catch (error) {
 61→    logError("proxy.anthropic.upstream_error", "Failed to reach Anthropic API", error);
 62→    return jsonError("upstream unreachable", 502);
 63→  }
 64→
 65→  if (!isStreaming) {
 66→    const responseBody = await upstream.text();
 67→    let responseData: unknown;
 68→    try {
 69→      responseData = JSON.parse(responseBody);
 70→    } catch {
 71→      // non-JSON response — forward as-is
 72→    }
 73→
 74→    logInfo("proxy.anthropic.response", "Anthropic response", {
 75→      status: upstream.status,
 76→      headers: Object.fromEntries(upstream.headers.entries()),
 77→      body: responseData ?? responseBody,
 78→      latency_ms: elapsedMs(startedAt),
 79→      ...identity,
 80→    });
 81→
 82→    return new Response(responseBody, {
 83→      status: upstream.status,
 84→      headers: {
 85→        "Content-Type": upstream.headers.get("content-type") ?? "application/json",
 86→        "Access-Control-Allow-Origin": "*",
 87→      },
 88→    });
 89→  }
 90→
 91→  // Streaming: pipe SSE events through, inspecting for usage data
 92→  const { readable, writable } = new TransformStream<Uint8Array>();
 93→  const writer = writable.getWriter();
 94→  const reader = upstream.body!.getReader();
 95→  const decoder = new TextDecoder();
 96→
 97→  const streamContext = {
 98→    model: parsed?.model,
 99→    inputTokens: 0,
100→    outputTokens: 0,
101→    stopReason: undefined as string | undefined,
102→  };
103→
104→  (async () => {
105→    try {
106→      let buffer = "";
107→      while (true) {
108→        const { done, value } = await reader.read();
109→        if (done) break;
110→
111→        // Forward raw bytes immediately
112→        await writer.write(value);
113→
114→        // Inspect for usage data (non-blocking parse)
115→        buffer += decoder.decode(value, { stream: true });
116→        buffer = extractSSEUsage(buffer, streamContext);
117→      }
118→    } catch (error) {
119→      logError("proxy.anthropic.stream_error", "SSE relay error", error);
120→    } finally {
121→      await writer.close();
122→
123→      logInfo("proxy.anthropic.response", "Anthropic stream complete", {
124→        model: streamContext.model,
125→        input_tokens: streamContext.inputTokens,
126→        output_tokens: streamContext.outputTokens,
127→        stop_reason: streamContext.stopReason,
128→        latency_ms: elapsedMs(startedAt),
129→        ...identity,
130→      });
131→    }
132→  })();
133→
134→  return new Response(readable, {
135→    status: upstream.status,
136→    headers: {
137→      "Content-Type": "text/event-stream",
138→      "Cache-Control": "no-cache",
139→      "Connection": "keep-alive",
140→      "X-Accel-Buffering": "no",
141→      "Access-Control-Allow-Origin": "*",
142→    },
143→  });
144→}
145→
146→// Parses Claude Code's metadata.user_id format:
147→// "user_<hash>_account_<uuid>_session_<uuid>"
148→function parseMetadataUserId(userId?: string): { user_hash?: string; account_id?: string; session_id?: string } {
149→  if (!userId) return {};
150→  const match = userId.match(/^user_([a-f0-9]+)_account_([a-f0-9-]+)_session_([a-f0-9-]+)$/);
151→  if (!match) return { user_hash: userId };
152→  return {
153→    user_hash: match[1],
154→    account_id: match[2],
155→    session_id: match[3],
156→  };
157→}
158→
159→type StreamContext = {
160→  model?: string;
161→  inputTokens: number;
162→  outputTokens: number;
163→  stopReason?: string;
164→};
165→
166→function extractSSEUsage(buffer: string, ctx: StreamContext): string {
167→  const lines = buffer.split("\n");
168→  // Keep the last incomplete line in the buffer
169→  const remainder = lines.pop() ?? "";
170→
171→  for (const line of lines) {
172→    if (!line.startsWith("data: ")) continue;
173→    const data = line.slice(6);
174→    if (data === "[DONE]") continue;
175→
176→    try {
177→      const event = JSON.parse(data);
178→
179→      // message_start contains input token count
180→      if (event.type === "message_start" && event.message?.usage) {
181→        ctx.inputTokens = event.message.usage.input_tokens ?? 0;
182→        ctx.model = event.message.model ?? ctx.model;
183→      }
184→
185→      // message_delta contains output token count and stop reason
186→      if (event.type === "message_delta") {
187→        if (event.usage?.output_tokens) {
188→          ctx.outputTokens = event.usage.output_tokens;
189→        }
190→        if (event.delta?.stop_reason) {
191→          ctx.stopReason = event.delta.stop_reason;
192→        }
193→      }
194→    } catch {
195→      // partial JSON or non-JSON data line — skip
196→    }
197→  }
198→
199→  return remainder;
200→}
